import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { BehaviorSubject } from 'rxjs';
import { environment } from '../../../environments/environment';
import decode from 'jwt-decode';

@Injectable({ providedIn: 'root' })
export class ImpersonationService {
  private _isImpersonating$ = new BehaviorSubject<boolean>(!!localStorage.getItem('admin_token'));
  readonly isImpersonating$ = this._isImpersonating$.asObservable();

  constructor(private http: HttpClient) {}

  isImpersonating(): boolean {
    return this._isImpersonating$.value;
  }

  getImpersonatedUser(): { name: string; role: string } | null {
    if (!this.isImpersonating()) return null;
    const token = localStorage.getItem('token');
    if (!token) return null;
    try {
      const p = decode(token) as any;
      return { name: p.name || '', role: p.role || '' };
    } catch {
      return null;
    }
  }

  startImpersonation(userId: number, targetType?: 'user' | 'vendor' | 'factory'): void {
    this.http
      .post<{ token: string }>(`${environment.url}/api/admin/impersonate/${userId}`, targetType ? { targetType } : {})
      .subscribe({
        next: ({ token }) => {
          localStorage.setItem('admin_token', localStorage.getItem('token') || '');
          localStorage.setItem('token', token);
          this._isImpersonating$.next(true);
          window.location.href = '/';
        },
        error: (err) => {
          console.error('[ImpersonationService] start failed:', err);
        },
      });
  }

  stopImpersonation(): void {
    const adminToken = localStorage.getItem('admin_token');
    if (adminToken) {
      localStorage.setItem('token', adminToken);
    }
    localStorage.removeItem('admin_token');
    this._isImpersonating$.next(false);
    window.location.href = '/';
  }
}

