/* ====================================================================================
   📋  SECTION 301 - Controller Endpoints
   ==================================================================================== */

/**
 * Persist the Section 301 lookup to app_settings, then read it back and verify it
 * round-trips intact before the caller reports success.
 *
 * Why this exists: the upload handlers used to return the *parsed* summary right
 * after `AppSettingService.set(...)` without confirming the write actually landed.
 * So a save that silently failed, was rejected, or was truncated by the store still
 * reported "N codes loaded" to the admin — while `getSection301Status` then read back
 * nothing (or unparseable JSON) and every `lookupSection301` 404'd ("The requested
 * item was not found"). Verifying the round-trip turns a silent false-success into a
 * loud, specific error that names what actually happened.
 *
 * @param {object} lookup parsed `{ HTS: { list, rate, description } }` map
 * @returns {number} the verified code count read back from the store
 * @throws {Error} if the value is missing, unparseable, or short on read-back
 */
async function persistSection301Lookup(lookup) {
  const expected = Object.keys(lookup).length;
  await AppSettingService.set('section301_lookup', JSON.stringify(lookup));

  const raw = await AppSettingService.get('section301_lookup');
  if (!raw) {
    throw new Error(
      `Section 301 save failed: parsed ${expected} codes but read back nothing. ` +
      `The app_settings store did not retain the value.`
    );
  }
  let stored;
  try {
    stored = JSON.parse(raw);
  } catch (e) {
    throw new Error(
      `Section 301 save failed: parsed ${expected} codes but the stored value did not ` +
      `parse back as JSON (read-back length ${raw.length}). It was likely truncated or ` +
      `corrupted in storage.`
    );
  }
  const got = Object.keys(stored).length;
  if (got !== expected) {
    throw new Error(
      `Section 301 save failed: parsed ${expected} codes but only ${got} read back. ` +
      `The app_settings store truncated or rejected part of the value.`
    );
  }
  return got;
}

/**
 * POST /api/admin/section301/upload
 * Accepts a multipart PDF upload (field name: "pdf"), parses Section 301 tariff data,
 * stores the resulting lookup JSON in app_settings under the key "section301_lookup".
 *
 * Returns: { codesFound: number, lists: string[] }
 */
async function uploadSection301(req, res) {
  try {
    if (!req.file || !req.file.buffer) {
      return res.status(400).json({ error: 'No PDF file uploaded. Send as multipart field "pdf".' });
    }
    if (!req.file.mimetype.includes('pdf') && !req.file.originalname.toLowerCase().endsWith('.pdf')) {
      return res.status(400).json({ error: 'Uploaded file must be a PDF.' });
    }

    // Parse PDF → lookup object
    const lookup = await parsePdf(req.file.buffer);
    const codesFound = Object.keys(lookup).length;

    if (codesFound === 0) {
      return res.status(422).json({
        error: 'No HTS codes were found in the PDF. Check that this is a USTR Section 301 tariff list.',
      });
    }

    // Store in app_settings, verifying the write round-trips before reporting success.
    const storedCount = await persistSection301Lookup(lookup);

    // Summarise which lists were found
    const lists = [...new Set(Object.values(lookup).map(v => v.list))].sort();

    res.json({ codesFound: storedCount, lists });
  } catch (err) {
    console.error('[section301/upload] error:', err.message);
    res.status(500).json({ error: err.message });
  }
}

/**
 * POST /api/admin/section301/upload-csv
 * Preferred over the PDF uploader: takes a USTR Section 301 CSV (`HTS,Description,List`
 * columns; preamble and repeated headers tolerated). Parsing is column-addressed,
 * so codes are never silently mis-assigned to the wrong list the way the regex
 * PDF parser can be. List 4B rows are imported with rate 0 and labeled
 * "List 4B (suspended)" because that list was announced but never enacted.
 *
 * Multipart field name: "csv".
 *
 * Response:
 *   { codesFound, lists, skipped, conflicts, lineErrors }
 */
async function uploadSection301Csv(req, res) {
  try {
    if (!req.file || !req.file.buffer) {
      return res.status(400).json({ error: 'No CSV file uploaded. Send as multipart field "csv".' });
    }
    const lower = req.file.originalname.toLowerCase();
    const looksCsv = req.file.mimetype.includes('csv')
                  || req.file.mimetype.includes('text/plain')
                  || lower.endsWith('.csv');
    if (!looksCsv) {
      return res.status(400).json({ error: 'Uploaded file must be a .csv.' });
    }

    const text = req.file.buffer.toString('utf8');
    const { lookup, summary } = parseSection301Csv(text);

    if (summary.codesFound === 0) {
      return res.status(422).json({
        error: 'No HTS codes were found in the CSV. Check the file has "HTS,Description,List" columns.',
        summary,
      });
    }

    // Verify the write actually round-trips before reporting success. A clean parse
    // summary alone does not prove the data persisted (see persistSection301Lookup).
    const storedCount = await persistSection301Lookup(lookup);
    res.json({ ...summary, storedCount });
  } catch (err) {
    console.error('[section301/upload-csv] error:', err.message);
    res.status(500).json({ error: err.message });
  }
}

/**
 * GET /api/admin/section301/status
 * Returns a summary of the currently stored Section 301 data without
 * sending the full lookup JSON.
 *
 * Returns: { loaded: true, codesFound: number, lists: string[] }
 *       or { loaded: false } if no data has been uploaded yet.
 */
async function getSection301Status(req, res) {
  try {
    const raw = await AppSettingService.get('section301_lookup');
    if (!raw) {
      return res.json({ loaded: false });
    }
    let lookup;
    try {
      lookup = JSON.parse(raw);
    } catch {
      return res.json({ loaded: false });
    }
    const codesFound = Object.keys(lookup).length;
    const lists = [...new Set(Object.values(lookup).map(v => v.list))].sort();
    res.json({ loaded: true, codesFound, lists });
  } catch (err) {
    console.error('[section301/status] error:', err.message);
    res.status(500).json({ error: err.message });
  }
}

/**
 * GET /api/admin/section301/lookup?hts=NNNN.NN.NNNN
 * Look up a single HTS code in the stored Section 301 data.
 *
 * Resolution order: admin-curated overrides (app_settings.section301_overrides)
 * are checked first — admins use them to fix codes that the PDF parser
 * mis-assigned to the wrong list. Falls through to the regex-parsed lookup
 * from the uploaded PDF.
 *
 * Returns: { hts: string, list: string, rate: number, description: string, source: 'override'|'pdf' }
 *          or 404 if not found, or 400 if no data has been uploaded yet.
 */
async function lookupSection301(req, res) {
  try {
    const { hts } = req.query;
    if (!hts) return res.status(400).json({ error: 'hts query param is required' });

    // 1. Admin overrides — checked first so they can correct PDF-parse errors
    //    without re-uploading. Keys may be 8- or 10-digit; we use the same
    //    normalize-and-fall-back lookup logic as the main store.
    const overridesRaw = await AppSettingService.get('section301_overrides');
    if (overridesRaw) {
      let overrides;
      try { overrides = JSON.parse(overridesRaw); } catch { overrides = null; }
      if (overrides && typeof overrides === 'object') {
        const hit = lookupCode(overrides, hts.trim());
        if (hit) {
          return res.json({ hts, found: true, source: 'override', ...hit });
        }
      }
    }

    const raw = await AppSettingService.get('section301_lookup');
    if (!raw) {
      return res.status(400).json({
        error: 'Section 301 data has not been uploaded yet. Go to Editor → AI Settings to upload the PDF.',
      });
    }

    let lookup;
    try {
      lookup = JSON.parse(raw);
    } catch {
      return res.status(500).json({ error: 'Stored Section 301 data is corrupted. Please re-upload the PDF.' });
    }

    const result = lookupCode(lookup, hts.trim());
    if (!result) {
      return res.status(404).json({ hts, found: false });
    }

    res.json({ hts, found: true, source: 'pdf', ...result });
  } catch (err) {
    console.error('[section301/lookup] error:', err.message);
    res.status(500).json({ error: err.message });
  }
}

/* ====================================================================================
   📦  HTS RATES (MFN base tariff) - Controller Endpoints
   ==================================================================================== */

/**
 * GET /api/admin/hts-rates/status
 * Lightweight status of the bundled USITC HTS rate lookup.
 * Returns: { loaded: boolean, codesFound: number }
 */
async function getHtsRatesStatus(req, res) {
  try {
    res.json(htsRates.getStatus());
  } catch (err) {
    console.error('[hts-rates/status] error:', err.message);
    res.status(500).json({ error: err.message });
  }
}

/**
 * GET /api/admin/hts-rates/lookup?hts=NNNN.NN.NNNN
 * Look up the MFN general rate for the given HTS code. Falls back from
 * 10-digit → 8-digit → 6-digit prefix automatically.
 *
 * Returns: { hts, found, rate, rateText, description, matchType }
 *   - found=false (HTTP 200) when nothing in the schedule matches. A missing
 *     code is a normal lookup outcome, not a request error, so the caller can
 *     branch on `found` without the global HTTP error interceptor toasting it.
 *   - rate may be null even when found=true if the rate is not pure ad valorem
 *     (e.g. compound "13.5¢/kg + 4.4%"); the raw rateText is always returned
 */
async function lookupHtsRate(req, res) {
  try {
    const { hts } = req.query;
    if (!hts) return res.status(400).json({ error: 'hts query param is required' });
    const result = htsRates.lookupRate(hts.trim());
    if (!result.found) {
      return res.json({ hts, found: false, rate: null, rateText: null, description: null, matchType: null });
    }
    res.json({ ...result });
  } catch (err) {
    console.error('[hts-rates/lookup] error:', err.message);
    res.status(500).json({ error: err.message });
  }
}

