const TRUMP_2025_KEY = 'trump_2025_tariffs';

/**
 * GET /api/admin/trump2025/list
 * Return the full Trump 2025 country → rate list. Empty array if not yet configured.
 */
async function getTrump2025List(req, res) {
  try {
    const raw = await AppSettingService.get(TRUMP_2025_KEY);
    if (!raw) return res.json({ list: [] });
    try {
      const parsed = JSON.parse(raw);
      res.json({ list: Array.isArray(parsed) ? parsed : [] });
    } catch {
      // Corrupted record — recover by returning empty so the UI is still usable.
      res.json({ list: [] });
    }
  } catch (err) {
    console.error('[trump2025/list] error:', err.message);
    res.status(500).json({ error: err.message });
  }
}

/**
 * PUT /api/admin/trump2025/list
 * Replace the full Trump 2025 list. Body: { list: [{country, rate}, ...] }
 */
async function saveTrump2025List(req, res) {
  try {
    const { list } = req.body || {};
    let cleaned;
    try {
      cleaned = trump2025.parseList(list);
    } catch (e) {
      return res.status(400).json({ error: e.message });
    }
    await AppSettingService.set(TRUMP_2025_KEY, JSON.stringify(cleaned));
    res.json({ list: cleaned });
  } catch (err) {
    console.error('[trump2025/save] error:', err.message);
    res.status(500).json({ error: err.message });
  }
}

/**
 * GET /api/admin/trump2025/lookup?country=Vietnam
 * Look up the Trump 2025 rate for a given country.
 *
 * A country that isn't on the configured reciprocal-tariff list is a normal
 * lookup outcome (it simply has no Trump 2025 rate), not a request error, so
 * this returns found=false with HTTP 200. Returning 404 here made the RFQ
 * "Duty With $ and %" dialog fire a spurious global error toast on open.
 */
async function lookupTrump2025(req, res) {
  try {
    const { country } = req.query;
    if (!country) return res.status(400).json({ error: 'country query param is required' });
    const raw = await AppSettingService.get(TRUMP_2025_KEY);
    const list = raw ? JSON.parse(raw) : [];
    const result = trump2025.lookupRate(Array.isArray(list) ? list : [], country);
    if (!result.found) {
      return res.json({ found: false, country, rate: null, matchedAs: null });
    }
    res.json(result);
  } catch (err) {
    console.error('[trump2025/lookup] error:', err.message);
    res.status(500).json({ error: err.message });
  }
}

