/**
 * POST /api/admin/impersonate/:userId
 * Admin-only. Issues a short-lived JWT signed as the target user or vendor rep.
 * The token carries an extra `impersonated_by` claim (admin's user_id) for audit purposes.
 *
 * Returns: { token: string }
 */
async function startImpersonation(req, res) {
  try {
    const { userId } = req.params;
    const { targetType } = req.body || {};
    if (!userId) return res.status(400).json({ error: 'userId is required' });

    // Prevent impersonating while already impersonating
    const callerInfo = await getUserInfo(req.headers.authorization);
    if (callerInfo.impersonated_by) {
      return res.status(403).json({ error: 'Cannot impersonate while already in an impersonation session' });
    }

    const privateKey = process.env.JWT_PRIVATE_KEY;
    let tokenData;

    if (targetType === 'vendor') {
      const vendor = await sql.vendor.findOne({
        where: { vendor_id: userId },
        attributes: [
          'vendor_id',
          'vendor_name',
          'vendor_lastname',
          'vendor_email',
          'vendor_access',
          'vendor_company_nickname',
          'factory_id_fk',
        ],
      });
      if (!vendor) return res.status(404).json({ error: 'Vendor not found' });

      tokenData = {
        name: `${vendor.vendor_name || ''} ${vendor.vendor_lastname || ''}`.trim()
          || vendor.vendor_company_nickname
          || vendor.vendor_email
          || `Vendor ${vendor.vendor_id}`,
        user_id: vendor.vendor_id,
        email: vendor.vendor_email,
        role: 'vendor',
        access: vendor.vendor_access,
        factory_id: vendor.factory_id_fk,
        impersonated_by: callerInfo.user_id,
      };
    } else if (targetType === 'factory') {
      const factory = await sql.Factory.findOne({
        where: { id: userId },
        attributes: ['id', 'factory_name', 'factory_nickname', 'factory_access'],
      });
      if (!factory) return res.status(404).json({ error: 'Factory not found' });

      const vendor = await sql.vendor.findOne({
        where: { factory_id_fk: userId },
        attributes: [
          'vendor_id',
          'vendor_name',
          'vendor_lastname',
          'vendor_email',
          'vendor_access',
          'vendor_company_nickname',
          'factory_id_fk',
        ],
        order: [
          ['vendor_access', 'ASC'],
          ['vendor_id', 'ASC'],
        ],
      });

      tokenData = vendor ? {
        name: `${vendor.vendor_name || ''} ${vendor.vendor_lastname || ''}`.trim()
          || vendor.vendor_company_nickname
          || vendor.vendor_email
          || factory.factory_nickname
          || factory.factory_name
          || `Factory ${factory.id}`,
        user_id: vendor.vendor_id,
        email: vendor.vendor_email,
        role: 'vendor',
        access: vendor.vendor_access || factory.factory_access,
        factory_id: factory.id,
        impersonated_by: callerInfo.user_id,
      } : {
        name: factory.factory_nickname || factory.factory_name || `Factory ${factory.id}`,
        user_id: factory.id,
        email: null,
        role: 'vendor',
        access: factory.factory_access,
        factory_id: factory.id,
        impersonated_by: callerInfo.user_id,
      };
    } else {
      const targetUser = await sql.users.findOne({
        where: { id: userId },
        attributes: ['id', 'name', 'lastname', 'email', 'level'],
      });
      if (!targetUser) return res.status(404).json({ error: 'User not found' });

      tokenData = {
        name: `${targetUser.name || ''} ${targetUser.lastname || ''}`.trim(),
        user_id: targetUser.id,
        email: targetUser.email,
        role: targetUser.level,
        impersonated_by: callerInfo.user_id,
      };

      if (targetUser.level === 'vendor') {
        const vendor = await sql.vendor.findOne({
          where: { vendor_email: targetUser.email },
          attributes: ['vendor_access', 'factory_id_fk'],
        });
        if (vendor) {
          tokenData.access = vendor.vendor_access;
          tokenData.factory_id = vendor.factory_id_fk;
        }
      }
    }

    const token = jwt.sign(tokenData, privateKey, {
      algorithm: 'RS256',
      expiresIn: '2h',
    });

    res.json({ token });
  } catch (err) {
    console.error('[admin/impersonate] error:', err.message);
    res.status(500).json({ error: 'Impersonation failed' });
  }
}

