        {
          model: sql.UIElements,
          as: 'UIElement', // Ensure alias matches model association
          attributes: ['Id', 'Name', 'Type', 'ParentId']
        }
      ],
      order: [['Id', 'DESC']]
    });
  
    // Apply the mapping function to flatten the result
    return rolePermissions.map(permission => ({
      Id: permission.Id,
      RoleId: permission.RoleId,
      RoleName: permission.Role?.Name || null, // Flattened role name
