const jwt = require("jsonwebtoken");

function buildLoginTokenPayload(data) {
  const payload = {
    name: data.name + ' ' + data.lastname,
    user_id: data.id,
    email: data.email,
    role: data.level,
  };

  if (data.level == 'vendor') {
    payload.factory_id = data.factory_id;
  }

  return payload;
}

async function createLoginToken(req, data, options = {}) {
  const {
    comparePassword,
    jwtSign = jwt.sign,
    privateKey = process.env.JWT_PRIVATE_KEY,
  } = options;

  if (!req.passw || !data.passw) {
    return false;
  }

  if (typeof comparePassword !== 'function') {
    throw new Error('comparePassword is required to create a login token');
  }

  const passwordMatches = await comparePassword(req.passw, data.passw);
  if (!passwordMatches) {
    return false;
  }

  const tokenData = buildLoginTokenPayload(data);
  return jwtSign(tokenData, privateKey, {
    algorithm: 'RS256',
    expiresIn: req.remember ? "30days" : "12h",
  });
}

module.exports = {
  buildLoginTokenPayload,
  createLoginToken,
};

